/** Get all images across all restaurants as a flat array for collage */
export function getAllCulinaryImages(): CulinaryImage[] {
  return restaurants.flatMap((r) =>
    r.images.map((src) => ({
      src,
      alt: `${r.name} — ${r.propertyName}`,
      restaurant: r.slug,
      property: r.property,
    }))
  );
}

/** Get restaurants by property */
export function getRestaurantsByProperty(property: "tented-camp" | "springs" | "gardens") {
  return restaurants.filter((r) => r.property === property);
}

/** Get a curated selection for the collage (best images, no duplicates, mixed restaurants) */
export function getCollageImages(count: number = 24): CulinaryImage[] {
  const curated: CulinaryImage[] = [];
  for (const r of restaurants) {
    const take = r.images.length >= 3 ? 3 : r.images.length;
    for (let i = 0; i < take; i++) {
      curated.push({
        src: r.images[i],
        alt: `${r.name} — ${r.propertyName}`,
        restaurant: r.slug,
        property: r.property,
      });
    }
  }
  for (let i = curated.length - 1; i > 0; i--) {
    const j = Math.floor(Math.random() * (i + 1));
    [curated[i], curated[j]] = [curated[j], curated[i]];
  }
  return curated.slice(0, count);
}
